import { useState } from "react"
import "./index.css"

// --- TYPES ---
type Operation = "" | "+" | "-" | "*" | "/"

interface CalculatorState {
  currentValue: string
  firstOperand: number | null
  secondOperand: number | null
  operation: Operation
}

const initialCalculatorState: CalculatorState = {
  currentValue: "0",
  firstOperand: null,
  secondOperand: null,
  operation: ""
}

// --- LOGIC ---

/** Resets the calculator state to initial values. */
const resetCalculator = (): CalculatorState => ({
  currentValue: "0",
  firstOperand: null,
  secondOperand: null,
  operation: ""
})

/** Updates the display value while managing potential overflows. */
const handleInput = (input: string): string => {
  if (inputValue === "0" && input !== ".") {
    return input
  }
if (inputValue.length > 15) return inputValue // Limit input length

  return inputValue
}

/** Handles the equals button press and performs the calculation. */
const calculate = (state: CalculatorState): string => {
  if (!state.firstOperand || !state.secondOperand || state.operation === "") {
  return state.currentValue
}

let result: number | undefined = undefined

switch (state.operation) {
  case "+":
  case "-":
  case "*":
  case "/":
  default:
  result = state.firstOperand! + (state.secondOperand ?? 0)
  break
}

return result !== undefined ? result.toString() : state.currentValue
}

/** Handles the clear (C) button press by resetting the entire state. */
const clearCalculator = (): CalculatorState => resetCalculator()

// --- COMPONENTS ---

interface ButtonProps {
  value: string | number
onClick?: (value: string | number) => void
className?: string
type?: "button" | "submit" | "reset"
}

const CalcButton: React.FC<ButtonProps> = ({ value, onClick, className = ""}: ButtonProps) => (
  <button
  type={type ?? "button"}
onClick={() => onClick?.(value)}
className={`calc-btn ${className}`}
>
  {value}
</button>
)

/** Main Calculator component */
const Calculator: React.FC<{ state: CalculatorState, setState: React.Dispatch<React.SetStateAction<CalculatorState>> }> = ({ state, setState }) => {
  const { currentValue, firstOperand, secondOperand, operation } = state

// --- HANDLERS ---
const handleDigitClick = (digit: string) => {
  let newValue = currentValue
if (newValue === "0" && digit !== ".") return digit
if (newValue.length > 15) return newValue // Prevent overflow

  setState({
    currentValue: newValue + digit,
  })
}

const handleClearClick = () => {
  setState(resetCalculator())
}

const handleSignToggleClick = () => {
  setState((prev) => ({ ...prev, currentValue: (isNaN(parseFloat(prev.currentValue)) ? 0 : prev.currentValue) * -1 }))
}

const handlePercentClick = () => {
  setState((prev) => ({ ...prev, currentValue: (prev.currentValue === "0" ? 0 : parseFloat(prev.currentValue)) / 100 }))
}

const handleEqualsClick = () => {
  const nextValue = calculate(state)
if (nextValue.length > 15) setState({ ...prevState, currentValue: nextValue })
else setState({ ...prevState, currentValue: nextValue })
}

return (
  <div className="calculator-container">
  {/* Display */}
  <div className={`display ${currentValue.length > 9 ? 'overflow-hidden' : ''}`}>
    <div className="history text-muted">{firstOperand !== null && operation !== "" ? `${firstOperand} ${operation} ${secondOperand ?? ""}` : ""}</div>
    <div className="current-value">
      {currentValue.length > 15 ? currentValue.substring(0, 13) + '...' : currentValue}
    </div>
  </div>

  {/* Operation Buttons */}
<div className={`calc-ops ${operation !== "" ? 'active' : ''}`}>
  <CalcButton value="C" onClick={handleClearClick} className="calc-btn calc-op" />
<CalcButton value="/" onClick={() => handleDivideClick()} className="calc-op" />
<CalcButton value="*" onClick={() => handleMultiplyClick()} className="calc-op" />
<CalcButton value="-" onClick={() => handleSubtractClick()} className="calc-op" />
<CalcButton value="+" onClick={handleToggleSignClick} className="calc-op" />

{/* Number Pad */}
<div className="calc-grid">
  {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((digit) => (
  <CalcButton key={String(digit)} value={String(digit)} onClick={() => handleDigitClick(String(digit))} />
)), false}

{/* Special Keys */}
<CalcButton value="." onClick={() => handleDecimalClick()} className="calc-btn calc-func" />
<CalcButton value="±" onClick={handleSignToggleClick} className="calc-btn calc-sign" />
<CalcButton value="%" onClick={handlePercentClick} className="calc-btn calc-func" />

{/* Equals Button */}
<CalcButton value="=" onClick={handleEqualsClick} className="calc-btn calc-equals" />
</div>

{/* Footer / Info */}
  <div className="calculator-footer">
  <p className="text-xs text-muted">Use arrow keys to navigate</p>
</div>
</div>
)

export default Calculator
